scripts.inline:
echo '=== Image Details ===' && docker inspect --format 'ID: {{.Id}}
Created: {{.Created}}
Size: {{.Size}} bytes
Arch: {{.Architecture}}/{{.Os}}
Cmd: {{.Config.Cmd}}
Entrypoint: {{.Config.Entrypoint}}
ExposedPorts: {{json .Config.ExposedPorts}}
Labels: {{json .Config.Labels}}' "$IMAGE" && echo '' && echo '=== Layer History ===' && docker history --no-trunc --format 'table {{.CreatedBy}}\t{{.Size}}' "$IMAGE"
